using UnityEditor;
using UnityEngine;

var paths = new[] { "Assets/Art/Towers/barracks_tower.png", "Assets/Art/Soldiers/soldier_knight.png" };
foreach (var p in paths)
{
    var importer = AssetImporter.GetAtPath(p) as TextureImporter;
    if (importer != null)
    {
        Debug.Log($"[{p}] textureType={importer.textureType}, spriteMode={importer.spriteImportMode}, pixelsPerUnit={importer.spritePixelsPerUnit}, alphaSource={importer.alphaSource}, alphaIsTransparency={importer.alphaIsTransparency}");
        if (importer.textureType != TextureImporterType.Sprite)
        {
            Debug.Log($"  -> Fixing: setting textureType to Sprite");
            importer.textureType = TextureImporterType.Sprite;
            importer.spriteImportMode = SpriteImportMode.Single;
            importer.spritePixelsPerUnit = 100;
            importer.alphaSource = TextureImporterAlphaSource.FromInput;
            importer.alphaIsTransparency = true;
            importer.SaveAndReimport();
        }
    }
    else
    {
        Debug.Log($"[{p}] No TextureImporter found!");
    }

    var tex = AssetDatabase.LoadAssetAtPath<Texture2D>(p);
    if (tex != null) Debug.Log($"[{p}] size={tex.width}x{tex.height}, format={tex.format}");
}

