soldierData.soldierName = "Knight";
soldierData.maxHealth = 30;
soldierData.damage = 5;
soldierData.attackSpeed = 1f;
soldierData.attackRange = 1.2f;
soldierData.moveSpeed = 3f;
soldierData.engageRange = 3f;
soldierData.returnSpeed = 4f;
soldierData.respawnTime = 5f;

if (!System.IO.Directory.Exists("Assets/Resources/Data/Soldiers"))
    System.IO.Directory.CreateDirectory("Assets/Resources/Data/Soldiers");

AssetDatabase.CreateAsset(soldierData, "Assets/Resources/Data/Soldiers/Knight.asset");
AssetDatabase.SaveAssets();
Debug.Log("Created SoldierData: Assets/Resources/Data/Soldiers/Knight.asset");

// Create Barracks TowerData asset
