        slowDuration = 0,
        maxTargets = 7,
        pierceCount = 0
    }
};
towerData.soldierCountPerLevel = new int[] { 3, 5, 7 };

AssetDatabase.CreateAsset(towerData, "Assets/Resources/Data/Towers/Barracks.asset");
AssetDatabase.SaveAssets();
