using UnityEditor;
using UnityEngine;
using TowerDefense.Tower;
using TowerDefense.Data;

// === Create Soldier Prefab ===
var soldierObj = new GameObject("Soldier_Knight");
soldierObj.SetActive(false);

// Add SpriteRenderer
var sr = soldierObj.AddComponent<SpriteRenderer>();
var soldierSprite = AssetDatabase.LoadAssetAtPath<Sprite>("Assets/Art/Soldiers/soldier_knight.png");
if (soldierSprite != null)
{
    sr.sprite = soldierSprite;
    sr.sortingOrder = 5;
    Debug.Log("Soldier sprite set");
}
else
{
    Debug.LogWarning("Soldier sprite not found!");
}

// Add Soldier component
var soldier = soldierObj.AddComponent<Soldier>();

// Save as prefab
if (!System.IO.Directory.Exists("Assets/Prefabs/Soldiers"))
    System.IO.Directory.CreateDirectory("Assets/Prefabs/Soldiers");

var soldierPrefab = PrefabUtility.SaveAsPrefabAsset(soldierObj, "Assets/Prefabs/Soldiers/Soldier_Knight.prefab");
Debug.Log($"Soldier prefab saved: {(soldierPrefab != null ? "SUCCESS" : "FAILED")}");
Object.DestroyImmediate(soldierObj);

// === Create Barracks Tower Prefab ===
var towerObj = new GameObject("BarracksTower");
towerObj.SetActive(false);

// Add SpriteRenderer for tower visual
var towerSr = towerObj.AddComponent<SpriteRenderer>();
var towerSprite = AssetDatabase.LoadAssetAtPath<Sprite>("Assets/Art/Towers/barracks_tower.png");
if (towerSprite != null)
{
    towerSr.sprite = towerSprite;
    towerSr.sortingOrder = 2;
    Debug.Log("Tower sprite set");
}
else
{
    Debug.LogWarning("Tower sprite not found!");
}

// Add Tower component
var tower = towerObj.AddComponent<Tower>();

// Add BarracksAttack component
var barracksAttack = towerObj.AddComponent<BarracksAttack>();

// Set soldier data on BarracksAttack
var soldierData = AssetDatabase.LoadAssetAtPath<SoldierData>("Assets/Resources/Data/Soldiers/Knight.asset");
if (soldierData != null)
{
    // We need to use SerializedObject to set the private field
    var so = new SerializedObject(barracksAttack);
    var prop = so.FindProperty("_soldierData");
    if (prop != null)
    {
        prop.objectReferenceValue = soldierData;
        so.ApplyModifiedProperties();
        Debug.Log("SoldierData set on BarracksAttack");
    }
    else
    {
        Debug.LogWarning("_soldierData property not found");
    }
}

// Save as prefab
if (!System.IO.Directory.Exists("Assets/Prefabs/Towers"))
    System.IO.Directory.CreateDirectory("Assets/Prefabs/Towers");

var towerPrefab = PrefabUtility.SaveAsPrefabAsset(towerObj, "Assets/Prefabs/Towers/BarracksTower.prefab");
Debug.Log($"Barracks tower prefab saved: {(towerPrefab != null ? "SUCCESS" : "FAILED")}");
Object.DestroyImmediate(towerObj);

// === Update TowerData with prefab reference ===
var towerData = AssetDatabase.LoadAssetAtPath<TowerData>("Assets/Resources/Data/Towers/Barracks.asset");
if (towerData != null && towerPrefab != null)
{
    towerData.towerPrefab = towerPrefab;
    EditorUtility.SetDirty(towerData);
    AssetDatabase.SaveAssets();
    Debug.Log("TowerData.towerPrefab set");
}

// === Update SoldierData with prefab reference ===
if (soldierData != null && soldierPrefab != null)
{
    soldierData.soldierPrefab = soldierPrefab;
    var soldierIcon = AssetDatabase.LoadAssetAtPath<Sprite>("Assets/Art/Soldiers/soldier_knight.png");
