// Load the barracks tower prefab and add necessary components
var prefabPath = "Assets/Prefabs/Towers/BarracksTower.prefab";
var prefab = AssetDatabase.LoadAssetAtPath<GameObject>(prefabPath);
if (prefab == null)
{
    Debug.LogError("BarracksTower prefab not found!");
    return;
}

// We need to modify the prefab by instantiating, modifying, and saving back
var instance = (GameObject)PrefabUtility.InstantiatePrefab(prefab);
if (instance == null)
{
    Debug.LogError("Failed to instantiate prefab!");
    return;
}

// Add CircleCollider2D for tower slot click detection and physics
var collider = instance.GetComponent<CircleCollider2D>();
if (collider == null)
{
    collider = instance.AddComponent<CircleCollider2D>();
    collider.radius = 0.5f;
    collider.isTrigger = true;
    Debug.Log("Added CircleCollider2D");
}

// Ensure Tower component has references set
var tower = instance.GetComponent<Tower>();
if (tower != null)
{
    var attack = instance.GetComponent<BarracksAttack>();
    if (attack != null)
    {
        // Set the _attack field via SerializedObject
        var so = new SerializedObject(tower);
        var attackProp = so.FindProperty("_attack");
        if (attackProp != null)
        {
            attackProp.objectReferenceValue = attack;
            so.ApplyModifiedProperties();
            Debug.Log("Tower._attack set to BarracksAttack");
        }
    }
}

// Apply changes back to prefab
PrefabUtility.SaveAsPrefabAsset(instance, prefabPath);
Debug.Log("BarracksTower prefab updated with collider and component references");

// Clean up the instance
Object.DestroyImmediate(instance);

AssetDatabase.SaveAssets();

